example_bad:
fn create_greeting() -> &str {
    let s = String::from("hello");
    &s // Error: returns a reference to data owned by the function
}

fixes.code:
fn create_greeting() -> String {
    let s = String::from("hello");
    s // Return the owned String
}

fn create_greeting() -> &'static str {
    "hello" // String literals have 'static lifetime
}
